import { promises as fs } from 'fs';
import path from 'path';

const SRC_DIR = path.resolve(__dirname, '..', 'src');
const TARGET = '@i18n';
const REPLACEMENT = '@/i18n';

const walk = async (dir: string): Promise<string[]> => {
  const entries = await fs.readdir(dir, { withFileTypes: true });
  const files = await Promise.all(
    entries.map((entry) => {
      const fullPath = path.join(dir, entry.name);
      if (entry.isDirectory()) {
        return walk(fullPath);
      }
      if (entry.isFile()) {
        return [fullPath];
      }
      return [];
    })
  );
  return files.flat();
};

const replaceInFile = async (filePath: string): Promise<boolean> => {
  const original = await fs.readFile(filePath, 'utf8');
  if (!original.includes(TARGET)) {
    return false;
  }
  const updated = original.replaceAll(TARGET, REPLACEMENT);
  if (updated === original) {
    return false;
  }
  await fs.writeFile(filePath, updated, 'utf8');
  return true;
};

const main = async (): Promise<void> => {
  const files = await walk(SRC_DIR);
  let changed = 0;

  for (const file of files) {
    // Only touch files that actually change to avoid unnecessary writes
    if (await replaceInFile(file)) {
      changed += 1;
      console.log(`Updated ${file}`);
    }
  }

  console.log(`Done. Updated ${changed} file${changed === 1 ? '' : 's'}.`);
};

main().catch((error) => {
  console.error(error);
  process.exit(1);
});

